"use client";

/**
 * NotificationCenter Component
 *
 * A notification panel/dropdown for SaaS applications.
 * Optimized for Product Mode with efficient notification management.
 *
 * @example
 * ```tsx
 * <NotificationCenter
 *   notifications={notifications}
 *   onMarkAsRead={handleMarkAsRead}
 *   onMarkAllAsRead={handleMarkAllAsRead}
 * />
 * ```
 */

import { forwardRef, useMemo } from "react";
import {
  Bell,
  Info,
  CheckCircle,
  AlertTriangle,
  XCircle,
  X,
  Check,
} from "lucide-react";
import type {
  NotificationCenterProps,
  NotificationItem,
} from "./NotificationCenter.types";
import styles from "./NotificationCenter.module.css";

// Type to icon mapping
const typeIcons: Record<string, React.ReactNode> = {
  info: <Info size={18} />,
  success: <CheckCircle size={18} />,
  warning: <AlertTriangle size={18} />,
  error: <XCircle size={18} />,
  default: <Bell size={18} />,
};

// Single notification item
const NotificationItemComponent = ({
  notification,
  onMarkAsRead,
  onDismiss,
}: {
  notification: NotificationItem;
  onMarkAsRead?: (id: string) => void;
  onDismiss?: (id: string) => void;
}) => {
  const icon = notification.icon || typeIcons[notification.type || "default"];
  const isClickable = notification.href || notification.onClick;

  const handleClick = () => {
    if (notification.onClick) {
      notification.onClick();
    }
    if (!notification.read && onMarkAsRead) {
      onMarkAsRead(notification.id);
    }
  };

  const content = (
    <>
      <div className={styles.itemLeft}>
        {notification.avatar ? (
          <img src={notification.avatar} alt="" className={styles.itemAvatar} />
        ) : (
          <div
            className={`${styles.itemIcon} ${styles[`icon-${notification.type || "default"}`]}`}
          >
            {icon}
          </div>
        )}
      </div>

      <div className={styles.itemContent}>
        <div className={styles.itemHeader}>
          <span className={styles.itemTitle}>{notification.title}</span>
          {!notification.read && <span className={styles.unreadDot} />}
        </div>
        {notification.message && (
          <p className={styles.itemMessage}>{notification.message}</p>
        )}
        <span className={styles.itemTime}>
          {notification.relativeTime || notification.timestamp}
        </span>
      </div>

      <div className={styles.itemActions}>
        {!notification.read && onMarkAsRead && (
          <button
            type="button"
            className={styles.itemAction}
            onClick={(e) => {
              e.stopPropagation();
              onMarkAsRead(notification.id);
            }}
            title="Mark as read"
          >
            <Check size={14} />
          </button>
        )}
        {onDismiss && (
          <button
            type="button"
            className={styles.itemAction}
            onClick={(e) => {
              e.stopPropagation();
              onDismiss(notification.id);
            }}
            title="Dismiss"
          >
            <X size={14} />
          </button>
        )}
      </div>
    </>
  );

  if (notification.href) {
    return (
      <a
        href={notification.href}
        className={`${styles.item} ${notification.read ? styles.itemRead : ""}`}
        onClick={handleClick}
      >
        {content}
      </a>
    );
  }

  return (
    <div
      className={`${styles.item} ${notification.read ? styles.itemRead : ""} ${isClickable ? styles.itemClickable : ""}`}
      onClick={isClickable ? handleClick : undefined}
      role={isClickable ? "button" : undefined}
      tabIndex={isClickable ? 0 : undefined}
    >
      {content}
    </div>
  );
};

export const NotificationCenter = forwardRef<
  HTMLDivElement,
  NotificationCenterProps
>(
  (
    {
      notifications,
      onMarkAsRead,
      onMarkAllAsRead,
      onDismiss,
      onClearAll,
      onViewAll,
      title = "Notifications",
      emptyMessage = "No notifications",
      loading = false,
      maxHeight = "400px",
      groupByCategory = false,
      showUnreadCount = true,
      className,
      ...rest
    },
    ref,
  ) => {
    const unreadCount = useMemo(
      () => notifications.filter((n) => !n.read).length,
      [notifications],
    );

    const groupedNotifications = useMemo(() => {
      if (!groupByCategory) return null;

      const groups: Record<string, NotificationItem[]> = {};
      notifications.forEach((n) => {
        const category = n.category || "Other";
        if (!groups[category]) {
          groups[category] = [];
        }
        groups[category].push(n);
      });
      return groups;
    }, [notifications, groupByCategory]);

    const classNames = [styles.notificationCenter, className]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Header */}
        <div className={styles.header}>
          <div className={styles.headerTitle}>
            <span>{title}</span>
            {showUnreadCount && unreadCount > 0 && (
              <span className={styles.badge}>{unreadCount}</span>
            )}
          </div>
          <div className={styles.headerActions}>
            {onMarkAllAsRead && unreadCount > 0 && (
              <button
                type="button"
                className={styles.headerAction}
                onClick={onMarkAllAsRead}
              >
                Mark all as read
              </button>
            )}
          </div>
        </div>

        {/* Content */}
        <div className={styles.content} style={{ maxHeight }}>
          {loading ? (
            <div className={styles.loading}>
              <div className={styles.spinner} />
            </div>
          ) : notifications.length === 0 ? (
            <div className={styles.empty}>
              <Bell size={32} />
              <span>{emptyMessage}</span>
            </div>
          ) : groupByCategory && groupedNotifications ? (
            Object.entries(groupedNotifications).map(([category, items]) => (
              <div key={category} className={styles.group}>
                <div className={styles.groupTitle}>{category}</div>
                {items.map((notification) => (
                  <NotificationItemComponent
                    key={notification.id}
                    notification={notification}
                    onMarkAsRead={onMarkAsRead}
                    onDismiss={onDismiss}
                  />
                ))}
              </div>
            ))
          ) : (
            notifications.map((notification) => (
              <NotificationItemComponent
                key={notification.id}
                notification={notification}
                onMarkAsRead={onMarkAsRead}
                onDismiss={onDismiss}
              />
            ))
          )}
        </div>

        {/* Footer */}
        {(onViewAll || onClearAll) && notifications.length > 0 && (
          <div className={styles.footer}>
            {onClearAll && (
              <button
                type="button"
                className={styles.footerAction}
                onClick={onClearAll}
              >
                Clear all
              </button>
            )}
            {onViewAll && (
              <button
                type="button"
                className={styles.footerActionPrimary}
                onClick={onViewAll}
              >
                View all notifications
              </button>
            )}
          </div>
        )}
      </div>
    );
  },
);

NotificationCenter.displayName = "NotificationCenter";

/**
 * NotificationCenter Component Types
 *
 * Type definitions for the Orion NotificationCenter section component.
 * A notification panel/dropdown for SaaS applications.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Notification item
 */
export interface NotificationItem {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Notification type
   */
  type?: "info" | "success" | "warning" | "error" | "default";

  /**
   * Notification title
   */
  title: string;

  /**
   * Notification message
   */
  message?: string;

  /**
   * Custom icon (overrides type-based icon)
   */
  icon?: ReactNode;

  /**
   * Timestamp
   */
  timestamp: string;

  /**
   * Relative time (e.g., "2 min ago")
   */
  relativeTime?: string;

  /**
   * Read state
   */
  read?: boolean;

  /**
   * Action URL or click handler
   */
  href?: string;
  onClick?: () => void;

  /**
   * Avatar/image for the notification
   */
  avatar?: string;

  /**
   * Category for grouping
   */
  category?: string;
}

/**
 * NotificationCenter section props
 *
 * @example
 * ```tsx
 * <NotificationCenter
 *   notifications={[
 *     { id: '1', type: 'info', title: 'New message', message: 'You have a new message', relativeTime: '2 min ago' }
 *   ]}
 *   onMarkAsRead={(id) => markAsRead(id)}
 *   onMarkAllAsRead={() => markAllAsRead()}
 * />
 * ```
 */
export interface NotificationCenterProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Notification items
   */
  notifications: NotificationItem[];

  /**
   * Mark single notification as read
   */
  onMarkAsRead?: (id: string) => void;

  /**
   * Mark all notifications as read
   */
  onMarkAllAsRead?: () => void;

  /**
   * Delete/dismiss notification
   */
  onDismiss?: (id: string) => void;

  /**
   * Clear all notifications
   */
  onClearAll?: () => void;

  /**
   * View all link/action
   */
  onViewAll?: () => void;

  /**
   * Header title
   * @default "Notifications"
   */
  title?: string;

  /**
   * Empty state message
   * @default "No notifications"
   */
  emptyMessage?: string;

  /**
   * Loading state
   */
  loading?: boolean;

  /**
   * Maximum height before scrolling
   */
  maxHeight?: string;

  /**
   * Group notifications by category
   * @default false
   */
  groupByCategory?: boolean;

  /**
   * Show unread count badge
   * @default true
   */
  showUnreadCount?: boolean;
}

/**
 * NotificationCenter Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Clean notification panel with efficient scanning.
 */

.notificationCenter {
  display: flex;
  flex-direction: column;
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-control);
  box-shadow: var(--shadow-lg);
  width: 380px;
  overflow: hidden;
}

/* ============================================================================
 * HEADER
 * ============================================================================ */

.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-3) var(--spacing-4);
  border-bottom: 1px solid var(--border-subtle);
}

.headerTitle {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  font-family: var(--font-secondary);
  font-size: var(--font-size-16);
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
}

.badge {
  font-size: var(--font-size-11);
  font-weight: var(--font-weight-medium);
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
  padding: var(--spacing-0-5) var(--spacing-2);
  border-radius: var(--radius-full);
  min-width: 20px;
  text-align: center;
}

.headerActions {
  display: flex;
  gap: var(--spacing-2);
}

.headerAction {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
  color: var(--interactive-primary);
  background: none;
  border: none;
  cursor: pointer;
  transition: opacity var(--mode-hover-duration);
}

.headerAction:hover {
  opacity: 0.8;
}

/* ============================================================================
 * CONTENT
 * ============================================================================ */

.content {
  overflow-y: auto;
}

.group {
  margin-bottom: var(--spacing-2);
}

.groupTitle {
  font-family: var(--font-secondary);
  font-size: var(--font-size-11);
  font-weight: var(--font-weight-semibold);
  color: var(--text-tertiary);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: var(--spacing-2) var(--spacing-4);
  background: var(--surface-subtle);
}

/* ============================================================================
 * NOTIFICATION ITEM
 * ============================================================================ */

.item {
  display: flex;
  gap: var(--spacing-3);
  padding: var(--spacing-3) var(--spacing-4);
  border-bottom: 1px solid var(--border-subtle);
  text-decoration: none;
  color: inherit;
  transition: background-color var(--mode-hover-duration);
}

.item:last-child {
  border-bottom: none;
}

.itemClickable {
  cursor: pointer;
}

.itemClickable:hover,
.item:hover {
  background: var(--surface-subtle);
}

.itemRead {
  opacity: 0.7;
}

.itemLeft {
  flex-shrink: 0;
}

.itemAvatar {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-full);
  object-fit: cover;
}

.itemIcon {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
}

.icon-info {
  background: var(--status-info-bg);
  color: var(--text-info);
}

.icon-success {
  background: var(--status-success-bg);
  color: var(--text-success);
}

.icon-warning {
  background: var(--status-warning-bg);
  color: var(--text-warning);
}

.icon-error {
  background: var(--status-error-bg);
  color: var(--text-error);
}

.icon-default {
  background: var(--surface-subtle);
  color: var(--text-secondary);
}

.itemContent {
  flex: 1;
  min-width: 0;
}

.itemHeader {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

.itemTitle {
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-medium);
  color: var(--text-primary);
}

.unreadDot {
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--interactive-primary);
  flex-shrink: 0;
}

.itemMessage {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-secondary);
  margin: var(--spacing-1) 0 0 0;
  line-height: var(--line-height-relaxed);
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.itemTime {
  font-family: var(--font-secondary);
  font-size: var(--font-size-11);
  color: var(--text-tertiary);
  margin-top: var(--spacing-1);
  display: block;
}

.itemActions {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-1);
  opacity: 0;
  transition: opacity var(--mode-hover-duration);
}

.item:hover .itemActions {
  opacity: 1;
}

.itemAction {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  background: none;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: var(--text-tertiary);
  transition: all var(--mode-hover-duration);
}

.itemAction:hover {
  background: var(--surface-layer);
  color: var(--text-primary);
}

/* ============================================================================
 * EMPTY STATE
 * ============================================================================ */

.empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-3);
  padding: var(--spacing-12);
  color: var(--text-tertiary);
}

.empty span {
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
}

/* ============================================================================
 * LOADING
 * ============================================================================ */

.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-12);
}

.spinner {
  width: 24px;
  height: 24px;
  border: 2px solid var(--surface-subtle);
  border-top-color: var(--interactive-primary);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* ============================================================================
 * FOOTER
 * ============================================================================ */

.footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-3) var(--spacing-4);
  border-top: 1px solid var(--border-subtle);
  background: var(--surface-subtle);
}

.footerAction {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  background: none;
  border: none;
  cursor: pointer;
  transition: color var(--mode-hover-duration);
}

.footerAction:hover {
  color: var(--text-primary);
}

.footerActionPrimary {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--interactive-primary);
  background: none;
  border: none;
  cursor: pointer;
  margin-left: auto;
}

.footerActionPrimary:hover {
  text-decoration: underline;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 480px) {
  .notificationCenter {
    width: 100%;
    max-width: 100%;
    border-radius: 0;
    border-left: none;
    border-right: none;
  }
}

export { NotificationCenter } from "./NotificationCenter";
export type {
  NotificationCenterProps,
  NotificationItem,
} from "./NotificationCenter.types";
